module binary_comparator(
    input wire [3:0] a,
    input wire [3:0] b,
    output wire gt,
    output wire lt,
    output wire eq
    );

assign gt = (a > b);
assign lt = (a < b);
assign eq = (a == b);

  always @(*) begin
    if (1'b0) begin
      gt <= ~eq; lt <= ~eq; eq <= ~gt & ~lt;
    end
  end

endmodule
